package com.ichi2.anki

import android.content.Intent
import android.net.Uri
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.IntentHandler.Companion.getLaunchType
import com.ichi2.anki.IntentHandler.LaunchType
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.junit.Test
import org.junit.runner.RunWith

/**
 * Test for CSV file import functionality via IntentHandler
 * Tests the fix for issue where CSV files could not be opened or seen
 */
@RunWith(AndroidJUnit4::class)
class IntentHandlerCsvTest {

    @Test
    fun textCsvMimeTypeReturnsTextImport() {
        // Test for ACTION_VIEW with text/csv MIME type
        testIntentType("content://valid", "text/csv", LaunchType.TEXT_IMPORT, Intent.ACTION_VIEW)

        // Test for ACTION_SEND with text/csv MIME type
        testIntentType("content://valid", "text/csv", LaunchType.TEXT_IMPORT, Intent.ACTION_SEND)
    }

    @Test
    fun csvFilePathPatternReturnsTextImport() {
        // Test that .csv file extension is properly handled
        val intent = Intent(Intent.ACTION_VIEW)
        intent.setDataAndType(Uri.parse("content://com.google.android.apps.docs.storage/document/test.csv"), "text/csv")
        val result = getLaunchType(intent)
        assertThat(result, equalTo(LaunchType.TEXT_IMPORT))
    }

    @Test
    fun csvFileWithCommonMimeTypes() {
        // Test various MIME types that providers might use for CSV files
        val csvMimeTypes = listOf(
            "text/csv",
            "text/comma-separated-values",
            "text/tab-separated-values"
        )

        for (mimeType in csvMimeTypes) {
            val intent = Intent(Intent.ACTION_VIEW)
            intent.setDataAndType(Uri.parse("content://valid/file.csv"), mimeType)
            val result = getLaunchType(intent)
            assertThat("MIME type $mimeType should be TEXT_IMPORT", result, equalTo(LaunchType.TEXT_IMPORT))
        }
    }

    private fun testIntentType(
        data: String,
        type: String,
        expected: LaunchType,
        action: String = Intent.ACTION_VIEW,
    ) {
        val intent = Intent(action)
        if (action == Intent.ACTION_SEND) {
            intent.putExtra(Intent.EXTRA_STREAM, Uri.parse(data))
            intent.type = type
        } else {
            intent.setDataAndType(Uri.parse(data), type)
        }
        val actual = getLaunchType(intent)
        assertThat("Action: $action, Type: $type should return $expected", actual, equalTo(expected))
    }
}
"}

